{"code": "import json
from datetime import datetime

# Load the full result from the file
file_path = locals()['var_functions.query_db:8']
with open(file_path, 'r') as f:
    reviews = json.load(f)

# Function to parse various date formats
def parse_date(date_str):
    if not date_str:
        return None

    # Handle different formats
    formats = [
        '%Y-%m-%d %H:%M:%S',  # 2016-01-01 02:46:00
        '%Y-%m-%d %H:%M',      # 2016-01-01 02:46
        '%B %d, %Y at %I:%M %p',  # January 01, 2016 at 02:46 AM
        '%d %b %Y, %H:%M',     # 21 May 2016, 18:48
        '%d %b %Y, %I:%M %p',  # 21 May 2016, 09:43 PM
        '%B %d, %Y at %I:%M:%S %p',  # March 07, 2016 at 06:11:00 PM
        '%Y-%m-%d',            # 2016-01-01
        '%B %d, %Y',           # January 01, 2016
        '%d %b %Y'             # 21 May 2016
    ]

    for fmt in formats:
        try:
            return datetime.strptime(date_str, fmt)
        except:
            continue
    return None

# Parse reviews and filter by date range
start_date = datetime(2016, 1, 1)
end_date = datetime(2016, 6, 30, 23, 59, 59)

filtered_reviews = []
for review in reviews:
    date_obj = parse_date(review['date'])
    if date_obj and start_date <= date_obj <= end_date:
        filtered_reviews.append({
            'business_ref': review['business_ref'],
            'rating': int(review['rating']),
            'date': review['date']
        })

# Count reviews per business
from collections import defaultdict
review_counts = defaultdict(int)
for review in filtered_reviews:
    review_counts[review['business_ref']] += 1

# Filter businesses with at least 5 reviews in the date range
valid_businesses = {k: v for k, v in review_counts.items() if v >= 5}

print('__RESULT__:')
print(json.dumps({
    'total_filtered_reviews': len(filtered_reviews),
    'businesses_with_5plus_reviews': len(valid_businesses)
}))"}

